script:
frappe.ui.form.on("Hostel Admission", {
    refresh(frm) {
        if (!frm.is_new()) {
            frm.add_custom_button("Generate Hostel Fee", function () {
                frappe.new_doc("Hostel Fee", {
                    hostel_admission: frm.doc.name,
                    student: frm.doc.student,
                    hostel: frm.doc.hostel,
                    academic_year: frm.doc.academic_year,
                    amount: frm.doc.monthly_fee
                });
            }, "Create");
        }
    }
});
